// financial-report.component.ts
import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Expense, ExpenseService } from '../../../services/Economico/expense.service';
import { MonthlyRevenue, RevenueService } from '../../../services/Economico/revenue.service';
import { LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-financial-report',
  templateUrl: './financial-report.html',
  styleUrls: ['./financial-report.css'],
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule]
})
export class FinancialReport implements OnInit {
  private expenseService = inject(ExpenseService);
  private revenueService = inject(RevenueService);

  // Dati
  expenses: Expense[] = [];
  monthlyRevenue: MonthlyRevenue | null = null;
  availableMonths: string[] = [];
  
  // Filtri
  selectedMonth: string = this.getCurrentMonth();
  averageTicket: number = 25; // Scontrino medio predefinito - modificabile dall'utente
  
  // Modals
  showRevenueModal = false;
  showMonthsModal = false;
  
  // Form data per entrate manuali
  revenueForm = {
    description: '',
    amount: 0,
    category: 'altre_entrate',
    month: this.getCurrentMonth(),
    notes: ''
  };

  // Categorie per entrate manuali
  revenueCategories = [
    'vendite_dirette',
    'catering',
    'eventi',
    'altro_servizio',
    'altre_entrate'
  ];

  ngOnInit() {
    this.loadData();
  }

  async loadData() {
    await this.loadExpenses();
    await this.loadRevenue();
    await this.loadAvailableMonths();
  }

  async loadExpenses() {
    await this.expenseService.loadExpensesForMonth(this.selectedMonth);
    this.expenseService.data$.subscribe(expenses => {
      this.expenses = expenses;
    });
  }

  async loadRevenue() {
    this.monthlyRevenue = await this.revenueService.loadMonthlyRevenue(this.selectedMonth);
  }

  async loadAvailableMonths() {
    const expenseMonths = await this.expenseService.getAvailableMonths();
    const revenueMonths = await this.revenueService.getAvailableMonths();
    
    // Unisci e rimuovi duplicati
    this.availableMonths = [...new Set([...expenseMonths, ...revenueMonths])].sort().reverse();
  }

  // Statistiche calcolate
  get monthlyStats() {
    return this.expenseService.calculateMonthlyTotal(this.expenses);
  }

  get financialSummary() {
    const expenses = this.monthlyStats.totale;
    const revenue = this.monthlyRevenue?.net_revenue || 0;
    const profit = revenue - expenses;
    const profitMargin = revenue > 0 ? (profit / revenue) * 100 : 0;

    return {
      expenses,
      revenue,
      profit,
      profitMargin,
      breakEvenCustomers: expenses / this.averageTicket,
      actualCustomers: this.monthlyRevenue?.order_count || 0,
      customersDifference: (this.monthlyRevenue?.order_count || 0) - (expenses / this.averageTicket)
    };
  }

  get dailyBreakdown() {
    const summary = this.financialSummary;
    const daysInMonth = this.getDaysInMonth(this.selectedMonth);
    
    return {
      dailyExpenses: summary.expenses / daysInMonth,
      dailyRevenue: summary.revenue / daysInMonth,
      dailyProfit: summary.profit / daysInMonth,
      dailyCustomersNeeded: summary.breakEvenCustomers / daysInMonth,
      dailyActualCustomers: summary.actualCustomers / daysInMonth
    };
  }

  // Utility methods
  getCurrentMonth(): string {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-01`;
  }

  formatMonthDisplay(month: string): string {
    const date = new Date(month);
    return date.toLocaleDateString('it-IT', { month: 'long', year: 'numeric' });
  }

  formatCurrency(amount: number): string {
    return `€${amount.toFixed(2)}`;
  }

  formatNumber(num: number): string {
    return num.toFixed(0);
  }

  getDaysInMonth(month: string): number {
    const date = new Date(month);
    return new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  }

  // Gestione Modal
  openAddRevenueModal() {
    this.revenueForm = {
      description: '',
      amount: 0,
      category: 'altre_entrate',
      month: this.selectedMonth,
      notes: ''
    };
    this.showRevenueModal = true;
  }

  openMonthsModal() {
    this.showMonthsModal = true;
  }

  closeRevenueModal() {
    this.showRevenueModal = false;
  }

  closeMonthsModal() {
    this.showMonthsModal = false;
  }

  // CRUD Operations
  async saveRevenue() {
    if (!this.revenueForm.description || !this.revenueForm.amount) {
      alert('Compila tutti i campi obbligatori');
      return;
    }

    try {
      await this.revenueService.addManualRevenue(this.revenueForm);
      this.closeRevenueModal();
      await this.loadRevenue();
    } catch (error) {
      console.error('Error saving revenue:', error);
      alert('Errore nel salvataggio dell\'entrata: ' + (error as any).message);
    }
  }

  async changeMonth(month: string) {
    this.selectedMonth = month;
    await this.loadData();
    this.closeMonthsModal();
  }

  // Calcoli avanzati
  getCategoryBreakdown() {
    const categories = [...new Set(this.expenses.map(exp => exp.category))];
    
    return categories.map(category => {
      const categoryExpenses = this.expenses
        .filter(exp => exp.category === category)
        .reduce((sum, exp) => sum + exp.amount, 0);
      
      const percentage = this.monthlyStats.totale > 0 ? 
        (categoryExpenses / this.monthlyStats.totale) * 100 : 0;

      return {
        category,
        amount: categoryExpenses,
        percentage
      };
    }).sort((a, b) => b.amount - a.amount);
  }

  getProfitabilityStatus(): { status: string; color: string; message: string } {
    const summary = this.financialSummary;
    
    if (summary.profitMargin >= 20) {
      return {
        status: 'eccellente',
        color: 'success',
        message: 'Redditività eccellente!'
      };
    } else if (summary.profitMargin >= 10) {
      return {
        status: 'buona',
        color: 'info',
        message: 'Redditività buona'
      };
    } else if (summary.profitMargin >= 0) {
      return {
        status: 'accettabile',
        color: 'warning',
        message: 'Redditività accettabile'
      };
    } else {
      return {
        status: 'critica',
        color: 'danger',
        message: 'In perdita - Necessaria attenzione'
      };
    }
  }

  // Metodi helper per Math functions
min(a: number, b: number): number {
  return Math.min(a, b);
}

max(a: number, b: number): number {
  return Math.max(a, b);
}

// Metodo per calcolare la width della progress bar
getProgressWidth(): number {
  const margin = this.financialSummary.profitMargin;
  return Math.min(Math.max(margin, 0), 100);
}

}