// revenue.service.ts
import { Injectable, inject } from '@angular/core';
import { BaseService } from '../Base/base.service';
import { BehaviorSubject } from 'rxjs';

export interface RevenueData {
  id: string;
  restaurant_id: string;
  order_id: string;
  order_number: string;
  table_number?: string;
  customer_name: string;
  total_amount: number;
  tax_amount: number;
  discount_amount: number;
  net_amount: number;
  payment_method: string;
  order_type: 'dine_in' | 'takeaway' | 'delivery';
  completed_at: string;
  month: string; // Formato YYYY-MM-01 per il raggruppamento mensile
  created_at: string;
}

export interface MonthlyRevenue {
  month: string;
  total_revenue: number;
  total_tax: number;
  total_discount: number;
  net_revenue: number;
  order_count: number;
  average_ticket: number;
}

@Injectable({
  providedIn: 'root'
})
export class RevenueService extends BaseService<RevenueData> {
  protected getTableName(): string {
    return 'revenue_records'; // Tabella per entrate manuali
  }

  private monthlyRevenueSubject = new BehaviorSubject<MonthlyRevenue[]>([]);
  public monthlyRevenue$ = this.monthlyRevenueSubject.asObservable();

  // Carica i guadagni per un mese specifico (entrate manuali)
  async loadRevenueForMonth(month: string): Promise<RevenueData[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return [];

      const formattedMonth = this.formatMonthForDatabase(month);

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('month', formattedMonth)
        .order('completed_at', { ascending: false });

      if (error) throw error;
      this.dataSubject.next(data || []);
      return data || [];
    } catch (error) {
      console.error('Error loading revenue for month:', error);
      return [];
    }
  }

  // Calcola il guadagno totale mensile dagli ordini completati (tabella comande)
  async calculateMonthlyRevenueFromOrders(month: string): Promise<MonthlyRevenue> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return this.getEmptyMonthlyRevenue(month);

      const formattedMonth = this.formatMonthForDatabase(month);
      const startDate = `${formattedMonth.substring(0, 7)}-01`;
      const endDate = this.getLastDayOfMonth(formattedMonth);

      // Usa la tabella 'comande' (non 'orders')
      const { data: orders, error } = await this.supabaseService.getSupabaseClient()
        .from('comande')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('status', 'completed')
        .gte('created_at', `${startDate}T00:00:00`)
        .lte('created_at', `${endDate}T23:59:59`);

      if (error) throw error;

      const monthlyOrders = orders || [];
      
      const totalRevenue = monthlyOrders.reduce((sum, order) => sum + (order.total_amount || 0), 0);
      const totalTax = monthlyOrders.reduce((sum, order) => sum + (order.tax_amount || 0), 0);
      const totalDiscount = monthlyOrders.reduce((sum, order) => sum + (order.discount_amount || 0), 0);
      const netRevenue = totalRevenue - totalDiscount;
      const orderCount = monthlyOrders.length;
      const averageTicket = orderCount > 0 ? netRevenue / orderCount : 0;

      const monthlyRevenue: MonthlyRevenue = {
        month: formattedMonth,
        total_revenue: totalRevenue,
        total_tax: totalTax,
        total_discount: totalDiscount,
        net_revenue: netRevenue,
        order_count: orderCount,
        average_ticket: averageTicket
      };

      // Salva nel database per cache (opzionale)
      await this.saveMonthlyRevenue(monthlyRevenue);
      
      return monthlyRevenue;
    } catch (error) {
      console.error('Error calculating monthly revenue:', error);
      return this.getEmptyMonthlyRevenue(month);
    }
  }

  // Salva il revenue mensile per cache
  private async saveMonthlyRevenue(monthlyRevenue: MonthlyRevenue): Promise<void> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return;

      const { error } = await this.supabaseService.getSupabaseClient()
        .from('monthly_revenue')
        .upsert({
          restaurant_id: restaurantId,
          ...monthlyRevenue,
          updated_at: new Date().toISOString()
        }, {
          onConflict: 'restaurant_id,month'
        });

      if (error) throw error;
    } catch (error) {
      console.error('Error saving monthly revenue:', error);
    }
  }

  // Carica revenue mensile dalla cache
  async loadMonthlyRevenue(month: string): Promise<MonthlyRevenue | null> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return null;

      const formattedMonth = this.formatMonthForDatabase(month);

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('monthly_revenue')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('month', formattedMonth)
        .maybeSingle(); // Usa maybeSingle invece di single per evitare errore se non trovato

      if (error) throw error;

      if (data) {
        return data;
      } else {
        // Se non trovato, calcola dagli ordini
        return await this.calculateMonthlyRevenueFromOrders(month);
      }
    } catch (error) {
      console.error('Error loading monthly revenue:', error);
      return await this.calculateMonthlyRevenueFromOrders(month);
    }
  }

  // Aggiungi un'entrata manuale
  async addManualRevenue(revenueData: {
    description: string;
    amount: number;
    category: string;
    month: string;
    notes?: string;
  }): Promise<RevenueData | null> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return null;

      const manualRevenue = {
        restaurant_id: restaurantId,
        order_id: `manual_${Date.now()}`,
        order_number: `MANUAL-${Date.now()}`,
        customer_name: 'Entrata Manuale',
        total_amount: revenueData.amount,
        tax_amount: 0,
        discount_amount: 0,
        net_amount: revenueData.amount,
        payment_method: 'manual',
        order_type: 'dine_in',
        description: revenueData.description,
        category: revenueData.category,
        notes: revenueData.notes,
        month: this.formatMonthForDatabase(revenueData.month),
        completed_at: new Date().toISOString(),
        created_at: new Date().toISOString()
      };

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .insert(manualRevenue)
        .select()
        .single();

      if (error) throw error;

      await this.loadRevenueForMonth(revenueData.month);
      return data;
    } catch (error) {
      console.error('Error adding manual revenue:', error);
      return null;
    }
  }

  // Elimina un'entrata manuale
  async deleteManualRevenue(revenueId: string): Promise<boolean> {
    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .delete()
        .eq('id', revenueId)
        .like('order_id', 'manual_%');

      if (error) throw error;
      return true;
    } catch (error) {
      console.error('Error deleting manual revenue:', error);
      return false;
    }
  }

  // Utility methods
  private formatMonthForDatabase(month: string): string {
    if (month.match(/^\d{4}-\d{2}-\d{2}$/)) {
      return month;
    }
    if (month.match(/^\d{4}-\d{2}$/)) {
      return `${month}-01`;
    }
    const date = new Date(month);
    return date.toISOString().split('T')[0];
  }

  private getLastDayOfMonth(month: string): string {
    const date = new Date(month);
    const lastDay = new Date(date.getFullYear(), date.getMonth() + 1, 0);
    return lastDay.toISOString().split('T')[0];
  }

  private getEmptyMonthlyRevenue(month: string): MonthlyRevenue {
    return {
      month: this.formatMonthForDatabase(month),
      total_revenue: 0,
      total_tax: 0,
      total_discount: 0,
      net_revenue: 0,
      order_count: 0,
      average_ticket: 0
    };
  }

  // Ottieni mesi disponibili con revenue
  async getAvailableMonths(): Promise<string[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return [];

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('month')
        .eq('restaurant_id', restaurantId)
        .order('month', { ascending: false });

      if (error) throw error;

      const uniqueMonths = [...new Set(data?.map(item => item.month) || [])];
      return uniqueMonths;
    } catch (error) {
      console.error('Error getting available months:', error);
      return [];
    }
  }
}